__kernel void reduce_kernel(long d_Ne, long d_no, int d_mul, fp *d_sums, fp *d_sums2, int blocks2_work_size) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int ei = (bx * NUMBER_THREADS) + tx;
    int nf = NUMBER_THREADS - ((get_num_groups(0) * NUMBER_THREADS) - d_no);
    int df = 0;
    int i;

    fp d_psum[NUMBER_THREADS];
    fp d_psum2[NUMBER_THREADS];

    if (ei < d_no) {
        d_psum[tx] = d_sums[ei * d_mul];
        d_psum2[tx] = d_sums2[ei * d_mul];
    } else {
        d_psum[tx] = 0.0f;
        d_psum2[tx] = 0.0f;
    }

    if (nf == NUMBER_THREADS) {
        for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
            if ((tx + 1) % i == 0) {
                d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }

        if (tx == (NUMBER_THREADS - 1)) {
            d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
            d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
        }
    } else {
        if (bx != (get_num_groups(0) - 1)) {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if ((tx + 1) % i == 0) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (NUMBER_THREADS - 1)) {
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        } else {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (i = 2; i <= df; i = 2 * i) {
                if ((tx + 1) % i == 0 && tx < df) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (df - 1)) {
                for (i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                    d_psum[tx] = d_psum[tx] + d_sums[i];
                    d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                }
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        }
    }
}

__kernel void srad_kernel(fp lambda, int Nr, int Nc, long Ne, int *d_iN, int *d_iS, int *d_jE, int *d_jW, fp *d_dN, fp *d_dS, fp *d_dW, fp *d_dE, fp q0sqr, fp *d_c, fp *d_I) {
    int idx = get_group_id(0) * NUMBER_THREADS + get_local_id(0);

    if (idx < Ne) {
        int i = idx / Nc;
        int j = idx % Nc;
        int k = idx;

        fp Jc = d_I[k];
        fp dN_val = d_I[d_iN[i] * Nc + j] - Jc;
        fp dS_val = d_I[d_iS[i] * Nc + j] - Jc;
        fp dW_val = d_I[i * Nc + d_jW[j]] - Jc;
        fp dE_val = d_I[i * Nc + d_jE[j]] - Jc;

        d_dN[k] = dN_val;
        d_dS[k] = dS_val;
        d_dW[k] = dW_val;
        d_dE[k] = dE_val;

        fp G2 = (dN_val * dN_val + dS_val * dS_val + dW_val * dW_val + dE_val * dE_val) / (Jc * Jc);
        fp L = (dN_val + dS_val + dW_val + dE_val) / Jc;

        fp num = (0.5f * G2) - ((1.0f / 16.0f) * (L * L));
        fp den = 1.0f + (0.25f * L);
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        fp c_val = 1.0f / (1.0f + den);

        if (c_val < 0.0f) c_val = 0.0f;
        else if (c_val > 1.0f) c_val = 1.0f;

        d_c[k] = c_val;
    }
}

__kernel void srad2_kernel(fp lambda, int Nr, int Nc, long Ne, int *d_iN, int *d_iS, int *d_jE, int *d_jW, fp *d_dN, fp *d_dS, fp *d_dW, fp *d_dE, fp *d_c, fp *d_I) {
    int idx = get_group_id(0) * NUMBER_THREADS + get_local_id(0);

    if (idx < Ne) {
        int i = idx / Nc;
        int j = idx % Nc;
        int k = idx;

        fp cN = d_c[k];
        fp cS = d_c[d_iS[i] * Nc + j];
        fp cW = d_c[k];
        fp cE = d_c[i * Nc + d_jE[j]];

        fp D = cN * d_dN[k] + cS * d_dS[k] + cW * d_dW[k] + cE * d_dE[k];

        d_I[k] = d_I[k] + 0.25f * lambda * D;
    }
}

__kernel void compress_kernel(long d_Ne, fp *d_I) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int ei = (bx * NUMBER_THREADS) + tx;

    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255.0f;
